import { Filter, SlidersHorizontal } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { Category } from '@/data/products'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet'
import { Slider } from '@/components/ui/slider'
import { Label } from '@/components/ui/label'
import { Badge } from '@/components/ui/badge'

interface FilterState {
  categoryId: string
  sort: string
  priceRange: number[]
  difficulty: number | null
}

interface FilterBarProps {
  filters: FilterState
  setFilters: React.Dispatch<React.SetStateAction<FilterState>>
  categories: Category[]
}

export default function FilterBar({ filters, setFilters, categories }: FilterBarProps) {
  return (
    <div className="flex flex-col md:flex-row gap-4 justify-between items-stretch md:items-center mb-8 bg-card p-4 rounded-xl shadow-subtle border border-border/50">
      <div className="w-full flex-1 min-w-0 overflow-x-auto pb-3 custom-scrollbar flex gap-2 items-center md:pr-4">
        <Button
          variant={filters.categoryId === 'all' ? 'default' : 'secondary'}
          className={cn('rounded-full whitespace-nowrap shadow-none shrink-0')}
          onClick={() => setFilters((prev) => ({ ...prev, categoryId: 'all' }))}
        >
          Todos
        </Button>
        {categories.map((cat) => (
          <Button
            key={cat.id}
            variant={filters.categoryId === cat.id ? 'default' : 'secondary'}
            className={cn('rounded-full whitespace-nowrap shadow-none shrink-0')}
            onClick={() => setFilters((prev) => ({ ...prev, categoryId: cat.id }))}
          >
            {cat.name}
          </Button>
        ))}
      </div>

      <div className="w-full md:w-auto flex items-center gap-3 justify-between md:justify-end shrink-0 pt-2 md:pt-0 border-t md:border-t-0 border-border/50 md:pl-2">
        <Sheet>
          <SheetTrigger asChild>
            <Button variant="outline" className="gap-2 shrink-0 relative">
              <SlidersHorizontal className="w-4 h-4" />
              Filtros
              {((filters.priceRange[1] !== undefined ? filters.priceRange[1] : 200) < 200 ||
                filters.difficulty) && (
                <span className="w-2 h-2 rounded-full bg-primary absolute top-2 right-2"></span>
              )}
            </Button>
          </SheetTrigger>
          <SheetContent side="right" className="w-full sm:max-w-sm overflow-y-auto">
            <SheetHeader className="mb-6">
              <SheetTitle>Filtros Avançados</SheetTitle>
            </SheetHeader>

            <div className="space-y-8">
              <div className="space-y-4">
                <div className="flex justify-between items-center">
                  <Label className="text-base">Preço Máximo</Label>
                  <span className="font-semibold text-primary">
                    R$ {filters.priceRange[1] !== undefined ? filters.priceRange[1] : 200}
                  </span>
                </div>
                <Slider
                  max={200}
                  step={10}
                  value={[filters.priceRange[1] !== undefined ? filters.priceRange[1] : 200]}
                  onValueChange={(val) =>
                    setFilters((prev) => ({ ...prev, priceRange: [0, val[0]] }))
                  }
                />
                <div className="flex justify-between text-xs text-muted-foreground">
                  <span>R$ 0</span>
                  <span>R$ 200+</span>
                </div>
              </div>

              <div className="space-y-4">
                <Label className="text-base">Nível de Dificuldade</Label>
                <div className="flex flex-wrap gap-2">
                  {[1, 2, 3, 4, 5].map((level) => (
                    <Badge
                      key={level}
                      variant={filters.difficulty === level ? 'default' : 'outline'}
                      className="cursor-pointer px-3 py-1 text-sm"
                      onClick={() =>
                        setFilters((prev) => ({
                          ...prev,
                          difficulty: prev.difficulty === level ? null : level,
                        }))
                      }
                    >
                      Nível {level}
                    </Badge>
                  ))}
                </div>
              </div>

              <Button
                variant="outline"
                className="w-full"
                onClick={() =>
                  setFilters((prev) => ({ ...prev, priceRange: [0, 200], difficulty: null }))
                }
              >
                Limpar Filtros
              </Button>
            </div>
          </SheetContent>
        </Sheet>

        <div className="flex items-center gap-2 shrink-0">
          <Filter className="w-4 h-4 text-muted-foreground hidden lg:block shrink-0" />
          <Select
            value={filters.sort}
            onValueChange={(val) => setFilters((prev) => ({ ...prev, sort: val }))}
          >
            <SelectTrigger className="w-[180px] md:w-[200px]">
              <SelectValue placeholder="Ordenar por" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="relevantes">Mais relevantes</SelectItem>
              <SelectItem value="mais-vendidos">Mais Vendidos</SelectItem>
              <SelectItem value="menor-preco">Menor Preço</SelectItem>
              <SelectItem value="maior-preco">Maior Preço</SelectItem>
              <SelectItem value="recentes">Mais Recentes</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
    </div>
  )
}
