import { useState } from 'react'
import { Mail } from 'lucide-react'
import { Input } from '@/components/ui/input'
import { Button } from '@/components/ui/button'
import { useToast } from '@/hooks/use-toast'
import useCouponStore from '@/stores/useCouponStore'
import useSubscriberStore from '@/stores/useSubscriberStore'
import { sendWelcomeEmail } from '@/lib/email'

export default function Newsletter() {
  const { toast } = useToast()
  const { coupons } = useCouponStore()
  const { addSubscriber } = useSubscriberStore()
  const [email, setEmail] = useState('')

  const handleSubscribe = (e: React.FormEvent) => {
    e.preventDefault()

    if (email) {
      addSubscriber(email)

      const welcomeCoupon = coupons.find((c) => c.isWelcomeCoupon && c.isActive)
      if (welcomeCoupon) {
        const discountValue =
          welcomeCoupon.type === 'percentage'
            ? `${welcomeCoupon.value}%`
            : `R$ ${welcomeCoupon.value.toFixed(2).replace('.', ',')}`

        sendWelcomeEmail(email, 'Assinante', welcomeCoupon.code, discountValue)
      }

      toast({
        title: 'Inscrição confirmada!',
        description: 'Você receberá nossas novidades em breve.',
      })
      setEmail('')
    }
  }

  return (
    <section className="mt-20 bg-slate-100 dark:bg-slate-900 rounded-2xl p-8 md:p-12 text-center max-w-3xl mx-auto mb-10 border border-slate-300 dark:border-slate-800 shadow-md">
      <Mail className="w-10 h-10 text-primary mx-auto mb-4" />
      <h2 className="text-2xl md:text-3xl font-heading font-bold mb-4 text-slate-900 dark:text-slate-50">
        Assine nossa Newsletter
      </h2>
      <p className="text-slate-600 dark:text-slate-400 mb-6 font-medium">
        Receba atualizações sobre novos lançamentos, dicas de montagem e ofertas exclusivas.
      </p>
      <form className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto" onSubmit={handleSubscribe}>
        <Input
          placeholder="Seu melhor e-mail"
          type="email"
          required
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          className="bg-white dark:bg-slate-950 border-slate-300 dark:border-slate-700 text-slate-900 dark:text-slate-100 placeholder:text-slate-500 shadow-sm focus-visible:ring-primary h-12 font-medium"
        />
        <Button
          type="submit"
          size="lg"
          className="h-12 px-8 font-bold shadow-sm transition-transform hover:scale-[1.02]"
        >
          Cadastrar
        </Button>
      </form>
    </section>
  )
}
